// hardenVM removes dangerous global properties from the Otto VM to prevent
// code execution, resource exhaustion vectors, and information leakage.
// Only essential properties required for basic expression evaluation remain.
func hardenVM(vm *otto.Otto) {
	global := vm.Global()
	// Remove dangerous constructors and functions that enable code execution or side effects
	dangerousProps := []string{
		"eval",
		"Function",
		"setTimeout",
		"setInterval",
		"clearTimeout",
		"clearInterval",
		"console",
		"XMLHttpRequest",
		"fetch",
		"WebSocket",
		"alert",
		"confirm",
		"prompt",
		// Remove global constructors that could be abused for prototype pollution
		// or unintended object creation. Basic literals (true/false/null) are keywords
		// and remain usable. undefined/Infinity/NaN are preserved as they may be needed
		// in legitimate conditions (e.g., item.value === undefined).
		"Object",
		"Array",
		"String",
		"Number",
		"Boolean",
		"Date",
		"RegExp",
		"Error",
		"Math",
		"JSON",
		"Promise",
		"Map",
		"Set",
		"WeakMap",
		"WeakSet",
		"Symbol",
		"Proxy",
		"Reflect",
	}
	for _, prop := range dangerousProps {
		if err := global.Delete(prop); err != nil {
			panic(fmt.Sprintf("hardenVM: failed to delete dangerous property %q: %v", prop, err))
		}
	}
}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item with the current item exposed as global variable 'item'.
// Security hardening includes:
//   - VM isolation per item
//   - Removal of dangerous global properties
//   - Strict execution timeout (100ms) to prevent DoS
//   - Panic recovery for interrupt handling
// Returns filtered items where script evaluates to truthy, or error on failure.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	const scriptTimeout = 100 * time.Millisecond
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()
		hardenVM(vm)

		// Set up interrupt channel for timeout enforcement
		vm.Interrupt = make(chan func(), 1) // Buffered to prevent sender block

		// Coordinate timeout goroutine lifecycle
		done := make(chan struct{})
		timer := time.NewTimer(scriptTimeout)

		// Goroutine to enforce timeout without leaking resources
		go func() {
			select {
			case <-timer.C:
				// Non-blocking send to avoid goroutine leak if VM is discarded
				select {
				case vm.Interrupt <- func() { panic("script timeout") }:
				default:
				}
			case <-done:
				// Script completed early; clean up timer
				if !timer.Stop() {
					// Timer fired concurrently; drain channel
					select {
					case <-timer.C:
					default:
					}
				}
			}
		}()
		defer close(done) // Ensures goroutine cleanup on all paths

		// Inject current item into sandboxed environment
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to inject item: %w", err)
		}

		// Execute script with panic recovery for timeout/interrupts
		var value otto.Value
		var runErr error
		func() {
			defer func() {
				if r := recover(); r != nil {
					runErr = fmt.Errorf("script execution terminated: %v", r)
				}
			}()
			value, runErr = vm.Run(conditionScript)
		}()

		if runErr != nil {
			return nil, fmt.Errorf("script evaluation failed for item %v: %w", item, runErr)
		}

		// Convert result to boolean using JS truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("script result conversion failed for item %v: %w", item, err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

