package main

import (
	"context"
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// SECURITY: Each script execution is strictly limited to 100ms to prevent DoS attacks via infinite loops or resource exhaustion.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}
	const timeoutDuration = 100 * time.Millisecond // Strict per-item execution timeout

	for _, item := range items {
		// Create context with timeout for this item's execution
		ctx, cancel := context.WithTimeout(context.Background(), timeoutDuration)
		vm := otto.New()
		interruptChan := make(chan func(), 1) // Buffered to prevent goroutine leak
		vm.Interrupt = interruptChan

		// Timeout handler goroutine (self-cleaning via context)
		go func() {
			<-ctx.Done()
			if ctx.Err() == context.DeadlineExceeded {
				// Non-blocking interrupt send to avoid deadlock if VM already terminated
				select {
				case interruptChan <- func() { panic("script timeout") }:
				default:
				}
			}
		}()

		// Inject current item into VM context
		if err := vm.Set("item", item); err != nil {
			cancel()
			return nil, err
		}

		// Execute user-provided script
		value, err := vm.Run(conditionScript)
		cancel() // Always cancel context to clean up timeout goroutine

		if err != nil {
			return nil, err
		}

		// Evaluate result using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

