package main

import (
	"time"
	"github.com/robertkrimen/otto"
)

const scriptExecutionTimeout = 100 * time.Millisecond

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security measures:
// - Enforces strict execution timeout per item to prevent DoS via infinite loops
// - Uses isolated VM instance per item to prevent state leakage between evaluations
// - Relies on Otto's sandboxed environment (no filesystem/network access by default)
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()
		interruptChan := make(chan func(), 1)
		vm.Interrupt = interruptChan

		// Start timeout guard goroutine - terminates script execution after threshold
		go func() {
			time.Sleep(scriptExecutionTimeout)
			// Send panic-triggering function to interrupt channel
			// Otto catches this panic internally and converts to error
			interruptChan <- func() {
				panic("script execution timeout")
			}
		}()

		// Inject current item into JS context (isolated per evaluation)
		if err := vm.Set("item", item); err != nil {
			return nil, err
		}

		// Execute user-provided script with timeout protection
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, err // Propagate timeout/script errors immediately
		}

		// Convert JS result to boolean using JS truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

