package main

import (
	"github.com/robertkrimen/otto"
)

// deepCopyMap creates a deep copy of map[string]interface{} to prevent
// JavaScript scripts from modifying original data via Otto's live bindings.
// Handles nested maps and slices recursively. Other types are copied by value.
func deepCopyMap(m map[string]interface{}) map[string]interface{} {
	if m == nil {
		return nil
	}
	cp := make(map[string]interface{}, len(m))
	for k, v := range m {
		cp[k] = deepCopyValue(v)
	}
	return cp
}

func deepCopyValue(v interface{}) interface{} {
	switch val := v.(type) {
	case map[string]interface{}:
		return deepCopyMap(val)
	case []interface{}:
		return deepCopySlice(val)
	// Primitives (bool, string, int, float64, nil, etc.) are safe to copy by value
	default:
		return v
	}
}

func deepCopySlice(s []interface{}) []interface{} {
	if s == nil {
		return nil
	}
	cp := make([]interface{}, len(s))
	for i, v := range s {
		cp[i] = deepCopyValue(v)
	}
	return cp
}

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with a DEEP COPY of the current item exposed as global 'item'.
// This prevents scripts from modifying original data through Otto's live bindings.
// Items for which the script evaluates to a truthy JavaScript value are included in the result.
// Returns filtered items (original references, not copies) and any error encountered.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		// Create deep copy to isolate script execution from original data
		itemCopy := deepCopyMap(item)

		vm := otto.New()
		if err := vm.Set("item", itemCopy); err != nil {
			return nil, err
		}

		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, err
		}

		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			// Append ORIGINAL item (not the copy) to preserve caller's data integrity
			result = append(result, item)
		}
	}

	return result, nil
}

