package main

import (
	"time"
	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security measures:
// 1. Enforces a strict execution timeout (100ms) per script evaluation to prevent DoS via infinite loops
// 2. Uses isolated VM per item to prevent cross-item state contamination
// 3. Sandboxed execution environment (Otto VM has no access to host filesystem/network by default)
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	const scriptTimeout = 100 * time.Millisecond
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()

		// Inject current item as global 'item' variable
		if err := vm.Set("item", item); err != nil {
			return nil, err
		}

		// Setup timeout protection for script execution
		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt

		timer := time.AfterFunc(scriptTimeout, func() {
			// Trigger VM interruption via panic (Otto safely recovers this)
			interrupt <- func() {
				panic("script execution timeout")
			}
		})

		// Execute condition script
		value, err := vm.Run(conditionScript)
		timer.Stop() // Critical: prevent goroutine leak and spurious interrupts

		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

