package main

import (
	"encoding/json"
	"fmt"
	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// To prevent mutation of original items and ensure script isolation, each item is marshaled to JSON
// and injected as a fresh JavaScript object before evaluating the condition.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		// Marshal item to JSON to create a safe, isolated copy for the VM
		jsonData, err := json.Marshal(item)
		if err != nil {
			return nil, fmt.Errorf("failed to marshal item to JSON: %w", err)
		}

		vm := otto.New()

		// Construct script: inject item as JSON literal (valid JS object) then evaluate condition
		// jsonData is guaranteed valid JSON (subset of JS literals) and safely embedded
		fullScript := fmt.Sprintf(`var item = %s; %s`, string(jsonData), conditionScript)

		value, err := vm.Run(fullScript)
		if err != nil {
			return nil, fmt.Errorf("script execution failed for item: %w", err)
		}

		// Convert result using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("failed to convert script result to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

