package main

import (
	"fmt"
	"time"

	"github.com/robertkrimen/otto"
)

const scriptExecutionTimeout = 100 * time.Millisecond

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security measures:
//   - Enforces execution timeout per script evaluation to prevent DoS attacks
//   - Uses isolated VM instance per item to prevent cross-item contamination
//   - Validates script result type before boolean conversion
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()
		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt

		// Start timeout guard
		timer := time.AfterFunc(scriptExecutionTimeout, func() {
			// Send no-op interrupt function to halt execution
			interrupt <- func() {}
		})

		// Inject current item as global 'item' variable
		if err := vm.Set("item", item); err != nil {
			timer.Stop()
			return nil, fmt.Errorf("failed to inject item into VM: %w", err)
		}

		// Execute condition script
		value, err := vm.Run(conditionScript)
		timer.Stop() // Stop timer regardless of execution outcome

		// Handle execution errors (including timeouts)
		if err != nil {
			// Check for interrupt error via string matching since otto.InterruptError may not be exported in all versions
			if err.Error() == "interrupted" {
				return nil, fmt.Errorf("script execution exceeded %v timeout", scriptExecutionTimeout)
			}
			return nil, fmt.Errorf("script execution failed: %w", err)
		}

		// Convert result to boolean using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("invalid script return type (must be boolean-compatible): %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

