		if err := vm.Set("item", copiedItem); err != nil {
			return nil, err
		}

		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, err
		}

		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		// Append ORIGINAL item (not copied version) to preserve original types and structure
		if boolResult {
			result = append(result, item)
		}
	}

