// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security hardening: Enforces execution timeout per item to prevent DoS attacks via infinite loops or resource exhaustion.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	const scriptTimeout = 100 * time.Millisecond // Strict timeout per item evaluation
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()
		interruptChan := make(chan func(), 1) // Buffered to prevent timer goroutine leak; must be chan func() per otto.VM.Interrupt requirement
		vm.Interrupt = interruptChan

		// Start timeout guard
		timer := time.AfterFunc(scriptTimeout, func() {
			// Non-blocking send (buffered channel ensures no goroutine leak)
			// Otto requires func() signature; VM will generate "interrupted" error when this triggers
			interruptChan <- func() {}
		})

		// Inject current item into JS context
		if err := vm.Set("item", item); err != nil {
			timer.Stop()
			return nil, fmt.Errorf("failed to inject item into VM: %w", err)
		}

		// Execute user-provided script
		value, err := vm.Run(conditionScript)
		timer.Stop() // Always stop timer; safe even if already fired

		// Handle timeout: Otto returns exact error message "interrupted" on interrupt
		if err != nil {
			if err.Error() == "interrupted" {
				return nil, fmt.Errorf("script execution timeout after %v", scriptTimeout)
			}
			return nil, fmt.Errorf("script evaluation failed for item: %w", err)
		}

		// Convert result to boolean using JS truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("script result cannot be converted to boolean: %w", err)
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
