import (
	"bytes"
	"encoding/json"
	"time"

	"github.com/robertkrimen/otto"
)

const scriptTimeout = 100 * time.Millisecond

// deepCopyMap creates a deep copy of map[string]interface{} using JSON serialization
// to prevent script-induced side effects on original data. Returns error on non-serializable content.
func deepCopyMap(m map[string]interface{}) (map[string]interface{}, error) {
	var buf bytes.Buffer
	if err := json.NewEncoder(&buf).Encode(m); err != nil {
		return nil, err
	}
	var copy map[string]interface{}
	if err := json.NewDecoder(&buf).Decode(&copy); err != nil {
		return nil, err
	}
	return copy, nil
}

// FilterItems filters items using a JavaScript condition script with security hardening:
// 1. Per-item execution timeout (100ms) to prevent DoS via infinite loops
// 2. Deep-copied item injection to prevent script-induced mutation of original data
// 3. Original items preserved in result (only copies exposed to VM)
//
// Script convention:
// - Current item injected as global variable `item`
// - Script must evaluate to boolean/truthy value
// - Example script: `item.active == true`
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		// Create isolated copy to prevent script side effects on original data
		copiedItem, err := deepCopyMap(item)
		if err != nil {
			return nil, err
		}

		vm := otto.New()
		interrupt := make(chan func(), 1)
		vm.Interrupt = interrupt

		// Enforce execution timeout to mitigate DoS attacks
		go func() {
			time.Sleep(scriptTimeout)
			// Non-blocking send (buffered channel); panic safely caught by Otto
			select {
			case interrupt <- func() { panic("script timeout") }:
			default:
			}
		}()

		// Inject sanitized copy into VM context
		if err := vm.Set("item", copiedItem); err != nil {
			return nil, err
		}

		// Execute user-provided script with timeout protection
		value, err := vm.Run(conditionScript)
		if err != nil {
			return nil, err
		}

		// Convert result using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		// Preserve ORIGINAL item (not modified copy) in results
		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

