package main

import (
	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// Items where the script evaluates to a truthy value are included in the result.
// Script errors during evaluation for individual items are treated as falsy (item skipped),
// while critical setup errors (e.g., VM initialization) are returned immediately.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()

		// Inject current item as global 'item' variable
		if err := vm.Set("item", item); err != nil {
			// Critical error: item structure incompatible with VM (should not occur with valid maps)
			return nil, err
		}

		// Execute condition script
		value, err := vm.Run(conditionScript)
		if err != nil {
			// Script runtime error for this item (e.g., missing property access) → skip item
			continue
		}

		// Convert result to boolean using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			// Unlikely conversion error → skip item
			continue
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

