package main

import (
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security measures:
//   - Enforces 100ms execution timeout per script evaluation to prevent DoS via infinite loops
//   - Uses isolated VM per item to prevent state leakage between evaluations
//   - Sandboxed execution (Otto VM has no access to host filesystem/network by default)
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	const scriptTimeout = 100 * time.Millisecond
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()
		interruptChan := make(chan func(), 1)
		vm.Interrupt = interruptChan

		timer := time.NewTimer(scriptTimeout)
		doneChan := make(chan struct{})

		// Timeout handler goroutine
		go func() {
			select {
			case <-timer.C:
				// Trigger VM interrupt with panic (Otto catches and returns as error)
				interruptChan <- func() {
					panic("script execution timeout")
				}
			case <-doneChan:
				// Normal completion path - exit cleanly
			}
		}()

		// Cleanup resources for this iteration
		cleanup := func() {
			// Stop timer (non-blocking drain if already fired)
			if !timer.Stop() {
				// Drain timer channel if stop failed (timer already fired)
				select {
				case <-timer.C:
				default:
				}
			}
			close(doneChan)
		}

		// Inject current item into VM context
		if err := vm.Set("item", item); err != nil {
			cleanup()
			return nil, err
		}

		// Execute user-provided script
		value, err := vm.Run(conditionScript)
		cleanup() // Always cleanup resources before checking errors

		if err != nil {
			return nil, err
		}

		// Convert result to boolean using JavaScript truthiness rules
		boolResult, err := value.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

