const scriptExecutionTimeout = 100 * time.Millisecond

// FilterItems filters a slice of map[string]interface{} items using a JavaScript condition script.
// The script is evaluated once per item, with the current item exposed as the global variable 'item'.
// The script should evaluate to a truthy or falsy value; items for which the script is truthy are included in the result.
// Security measures:
// 1. Enforces execution timeout per item to prevent DoS via infinite loops
// 2. Uses buffered interrupt channel to avoid goroutine leaks
// 3. Minimal VM per item to isolate execution contexts
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	var result []map[string]interface{}

	for _, item := range items {
		vm := otto.New()
		// Set up interrupt channel with buffer to prevent goroutine leaks
		// Buffer size 1 ensures timeout goroutine never blocks indefinitely
		vm.Interrupt = make(chan func(), 1)

		// Start timeout guard goroutine
		go func(vm *otto.Otto) {
			time.Sleep(scriptExecutionTimeout)
			// Send interrupt function; Otto runtime will recover panic and return error
			// Safe to send even if VM has terminated (buffer absorbs value)
			vm.Interrupt <- func() {
